+    } opcode : 4;
+    bool rsv3 : 1;
+    bool rsv2 : 1;
+    bool rsv1 : 1;
+    bool fin : 1;
+
+    unsigned int len : 7;
+    bool mask : 1;
+  } __attribute__ ((__packed__));
+  union {
+    Header header;
