+	state_ = mask_byte1;
+      else if(frame.length > 0)
+	state_ = body;
+      else
+	return true;
+    }
+    else if(frame.header.len == 126){
+      frame.length = 0;
+      state_ = length_2bytes_left;
+    }
+    else{
+      frame.length = 0;
+      state_ = length_8bytes_left;
+    }
