+    frame.length |= ((uint64_t)(input&0xFF) << 56);
+    state_ = length_7bytes_left;
+    return boost::indeterminate;
+  case length_7bytes_left:
+    frame.length |= ((uint64_t)(input&0xFF) << 48);
+    state_ = length_6bytes_left;
+    return boost::indeterminate;
+  case length_6bytes_left:
